ps.pstext:
if !IsFeatureImplemented(FEAT_SME2) then EndOfDecode(Decode_UNDEF); end;
if sz == '1' && !IsFeatureImplemented(FEAT_SME_I16I64) then EndOfDecode(Decode_UNDEF); end;
let esize : integer{} = 32 << UInt(sz);
let v : integer = UInt('010'::Rv);
let n : integer = UInt(Zn::'0');
let m : integer = UInt(Zm::'0');
let offset : integer = UInt(o1::'00');
let nreg : integer{} = 2;

if !IsFeatureImplemented(FEAT_SME2) then EndOfDecode(Decode_UNDEF); end;
if sz == '1' && !IsFeatureImplemented(FEAT_SME_I16I64) then EndOfDecode(Decode_UNDEF); end;
let esize : integer{} = 32 << UInt(sz);
let v : integer = UInt('010'::Rv);
let n : integer = UInt(Zn::'00');
let m : integer = UInt(Zm::'00');
let offset : integer = UInt(o1::'00');
let nreg : integer{} = 4;

CheckStreamingSVEAndZAEnabled();
let VL : integer{} = CurrentVL();
let elements : integer = VL DIV esize;
let vectors : integer = VL DIV 8;
let vstride : integer = vectors DIV nreg;
let vbase : bits(32) = X{}(v);
var vec : integer = (UInt(vbase) + offset) MOD vstride;
var result : bits(VL);
vec = vec - (vec MOD 4);

for r = 0 to nreg-1 do
    let operand1 : bits(VL) = Z{}(n+r);
    let operand2 : bits(VL) = Z{}(m+r);
    for i = 0 to 3 do
        let operand3 : bits(VL) = ZAvector{}(vec + i);
        for e = 0 to elements-1 do
            let element1 : integer = UInt(operand1[(4 * e + i)*:(esize DIV 4)]);
            let element2 : integer = UInt(operand2[(4 * e + i)*:(esize DIV 4)]);
            let product : bits(esize) = (element1 * element2)[esize-1:0];
            result[e*:esize] = operand3[e*:esize] - product;
        end;
        ZAvector{VL}(vec + i) = result;
    end;
    vec = vec + vstride;
end;
